/-- A nonzero member of the real ground field. -/
def IsCADNonzeroGroundCoefficient {σ : Type} (C : MvPolynomial σ ℝ) : Prop :=
  C ≠ 0 ∧ IsCADGroundCoefficient C

/-- Proves the stated mathematical property of comp. -/
lemma comp {ι κ τ : Type*}
    {f : (ι → ℂ) → (κ → ℂ)} {g : (κ → ℂ) → (τ → ℂ)}
    (hg : IsPolynomialMap g) (hf : IsPolynomialMap f) :
    IsPolynomialMap (g ∘ f) :=
  Causalean.Mathlib.AlgebraicGeometry.PolynomialImageDimension.IsPolynomialMap.comp hg hf

/-- A genuine polynomial rank-open locus: a nonempty principal open set cut out
by nonvanishing of a nonzero observable-coordinate minor. -/
def IsPolynomialRankOpen (rankOpen : Set (CumVec ℝ)) : Prop :=
  ∃ minor : MvPolynomial (ℕ × ℕ) ℝ,
    minor ≠ 0 ∧ rankOpen.Nonempty ∧
    rankOpen = { t | MvPolynomial.eval (fun ra => t ra.1 ra.2) minor ≠ 0 }

/-- A Zariski-dense subset of the parameter space. -/
def IsZariskiDenseParam {m : ℕ} (U : Set (ParamSpace ℂ m)) : Prop :=
  zariskiClosureParam U = Set.univ

/-- Structural parameter space `Θ^b_{m,L} = R^{m+1} × R^{n(L-1)}`.  The three
components are the direct slope, the `m` latent-loading slopes, and the
source-cumulant weight family `(j, r) ↦ c_{jr}`.
@realizes Theta^right_{m,L},Theta^left_{m,L},theta,eta(coordinates (γ/δ, ρ/σ, c/d))
@realizes gamma(component `.1`)  @realizes rho_i(component `.2.1`)
@realizes delta(component `.1`)  @realizes sigma_i(component `.2.1`)
@realizes c_{jr},d_{jr}(component `.2.2 j r`) -/
abbrev ParamSpace (R : Type*) (m : ℕ) : Type _ :=
  R × (Fin m → R) × (Fin (m + 2) → ℕ → R)

