/-- Orbit of `θ` under the admissible source-swap `G_m` action (the admissible
relabelings of the middle latent block). -/
def admissibleOrbit {m : ℕ} (θ : ParamSpace ℂ m) : Set (ParamSpace ℂ m) :=
  { θ' | ∃ π : Equiv.Perm (Fin m), θ' = admissibleSourceSwap m π θ }

/-- Arrow-tagged `G_m`-orbit of `(b, θ)`: its images under all admissible swaps, every
member carrying the same tag `b`.  Right-tagged and left-tagged orbits are therefore
disjoint. -/
def arrowTaggedOrbit {R : Type*} (m : ℕ) (b : Arrow) (θ : ParamSpace R m) :
    Set (Arrow × ParamSpace R m) :=
  { p | ∃ π : Equiv.Perm (Fin m), p = admissibleSourceSwapTagged m π (b, θ) }

/-- Reverse the source order at the two fixed axes. -/
def axisSourceReversal (m : ℕ) : Equiv.Perm (Fin (m + 2)) :=
  Equiv.swap 0 (Fin.last (m + 1))

/-- The real exceptional locus in the finite observable coordinate space used by
the incidence handles: membership in `bar E_m(ℝ)` together with zero coordinates
off the retained band `2 ≤ r ≤ 2m+2`, `0 ≤ a ≤ r`. -/
def bandLimitedRealExceptionalLocus (m : ℕ) : Set (CumVec ℝ) :=
  { t | IsAtlasBandLimited m t ∧
      complexifyCumVec t ∈ genericCompatibilityClosure m }

/-- The paper's finite retained-coordinate parameter space, represented inside the
function-valued `ParamSpace` by pinning every off-band source weight to zero. -/
def bandSupportedParams {R : Type*} [Zero R] (m L : ℕ) : Set (ParamSpace R m) :=
  { θ | ∀ (j : Fin (m + 2)) (r : ℕ), (r < 2 ∨ L < r) → θ.2.2 j r = 0 }

