/-- The source index `i+1` belonging to the `i`-th latent loading. -/
def latentSourceIndex {m : ℕ} (i : Fin m) : Fin (m + 2) :=
  ⟨i + 1, by omega⟩

/-- The unordered finite-slope part of either arrow support. -/
def loadingSlopeMultiset {m : ℕ} (θ : ParamSpace ℂ m) : Multiset ℂ :=
  θ.1 ::ₘ (Finset.univ.val.map (fun i => θ.2.1 i))

/-- Defines the polynomial called the lower Forward Complex Rank Polynomial. -/
def lowerForwardComplexRankPolynomial (m : ℕ) : MvPolynomial (ParamCoord m) ℂ :=
  (lowerForwardContractionMinorPolynomial ℂ m).det

/-- One-order-lower truncation `K₋ = 2m + 1`.
@realizes K_-(K₋ = 2m+1) -/
def lowerOrder (m : ℕ) : ℕ := 2 * m + 1

/-- Defines the polynomial called the lower Reverse Complex Rank Polynomial. -/
def lowerReverseComplexRankPolynomial (m : ℕ) : MvPolynomial (ParamCoord m) ℂ :=
  (lowerReverseContractionMinorPolynomial ℂ m).det

/-- Defines the polynomial called the lower Reverse First Polynomial. -/
def lowerReverseFirstPolynomial {R : Type*} [CommRing R]
    (m : ℕ) (j : Fin (m + 2)) : MvPolynomial (ParamCoord m) R :=
  if h0 : j.1 = 0 then 1
  else if ha : j.1 = m + 1 then MvPolynomial.X (Sum.inl ())
  else MvPolynomial.X (Sum.inr (Sum.inl ⟨j.1 - 1, by omega⟩))

/-- Defines the polynomial called the lower Reverse Real Rank Polynomial. -/
def lowerReverseRealRankPolynomial (m : ℕ) : MvPolynomial (RealParamCoord m) ℝ :=
  (lowerReverseContractionMinorPolynomial ℝ m).det

/-- The coordinate-reversed selected contraction rows. -/
def lowerReverseWeightedContraction (m : ℕ) (η : ParamSpace ℂ m) :=
  (lowerReverseMinor m η).mulVec

/-- Defines the polynomial called the lower Slope Polynomial. -/
def lowerSlopePolynomial {R : Type*} [CommRing R] (m : ℕ) (j : Fin (m + 2)) :
    MvPolynomial (ParamCoord m) R :=
  if h0 : j.1 = 0 then MvPolynomial.X (Sum.inl ())
  else if ha : j.1 = m + 1 then 1
  else MvPolynomial.X (Sum.inr (Sum.inl ⟨j.1 - 1, by omega⟩))

/-- Proves the stated set-containment or membership property for mem fiber Correspondence self. -/
lemma mem_fiberCorrespondence_self {R : Type*} [Zero R] {m L : ℕ}
    {Φ : ParamSpace R m → CumVec R} {θ : ParamSpace R m}
    (hθ : θ ∈ bandSupportedParams m L) :
    θ ∈ fiberCorrespondence L Φ (Φ θ) := by
  exact ⟨hθ, fun _ _ _ _ _ => rfl⟩

/-- Number of independent sources `n = m + 2`.
@realizes n(n = m+2 sources) -/
def numSources (m : ℕ) : ℕ := m + 2

/-- Structural-parameter dimension `p_L = (m+2)L - 1`.
@realizes q_L,p_L(p_L = (m+2)L - 1) -/
def pDim (m L : ℕ) : ℕ := (m + 2) * L - 1

/-- Observable cumulant-coordinate dimension `q_L = L(L+3)/2 - 2`.
@realizes q_L,p_L(q_L = L(L+3)/2 - 2) -/
def qDim (L : ℕ) : ℕ := L * (L + 3) / 2 - 2

/-- Reverse atlas nonemptiness label `ε^left(t)`. -/
def realAtlasReverseLabel (m : ℕ) (t : CumVec ℝ) : Prop :=
  (realAtlasReverseSection m t).Nonempty

/-- Reverse atlas section over `t`: the `t`-fiber of `Γ_left` (local description of
`R^left_{m,K}(t) ∩ F^left`). -/
def realAtlasReverseSection (m : ℕ) (t : CumVec ℝ) : Set (ParamSpace ℝ m) :=
  { lam | (t, lam) ∈ realAtlasHandleReverse m }

/-- Restriction of an infinite cumulant vector to its retained coordinates. -/
def restrictCumBand (L : ℕ) (t : CumVec ℂ) : RetainedCumCoord L → ℂ :=
  fun p => t p.1.1 p.1.2.1

/-- Exchange the two observable coordinates in every cumulant block. -/
def reverseCumCoordinates (t : CumVec ℂ) : CumVec ℂ :=
  fun r a => if a ≤ r then t r (r - a) else t r a

