/-- The finite slopes in the forward parametrization: the direct slope followed by the latent slopes. -/
def rtsF {m : ℕ} (θ : ParamSpace ℂ m) : Multiset ℂ :=
  θ.1 ::ₘ (Finset.univ.val.map fun i => θ.2.1 i)

/-- The separated observable domain on which exactly one feasible arrow remains. -/
def separatedSelectorDomain (m : ℕ) : Set (CumVec ℝ) :=
  { t | (feasibleFiberFormula m (forwardCumulantMap m (2 * m + 2)) t ∧
          ¬ feasibleFiberFormula m (reverseCumulantMap m (2 * m + 2)) t) ∨
        (feasibleFiberFormula m (reverseCumulantMap m (2 * m + 2)) t ∧
          ¬ feasibleFiberFormula m (forwardCumulantMap m (2 * m + 2)) t) }

/-- The solution set of a finite system of polynomial sign conditions. -/
def signConditionSet {r : ℕ} (equations nonnegative positive : Finset (MvPolynomial (Fin r) ℝ)) :
    Set (CADSpace r) :=
  { x | (∀ P ∈ equations, MvPolynomial.eval x P = 0) ∧
        (∀ P ∈ nonnegative, 0 ≤ MvPolynomial.eval x P) ∧
        (∀ P ∈ positive, 0 < MvPolynomial.eval x P) }

